import { useCallback, useEffect, useReducer } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you use the memory functions on a calculator?", a: "M+ adds the current display value to memory, M- subtracts it, MR recalls the stored memory value, and MC clears memory." },
  { q: "What does the percentage button do on a calculator?", a: "The percentage button divides the current number by 100, turning 25 into 0.25." },
  { q: "How do you calculate negative numbers?", a: "Use the sign change button to switch the current display between positive and negative." },
  { q: "What is the order of operations in a calculator?", a: "This simple calculator behaves like a handheld calculator and evaluates the current operation when you press another operator or equals." },
  { q: "How is an online calculator different from a physical one?", a: "An online calculator runs in your browser, needs no download, and works across devices while offering the same basic arithmetic functions." },
];

type Op = "+" | "-" | "*" | "/" | null;

const DIVIDE = "/";
const MULTIPLY = "x";

type CalcState = {
  display: string;
  stored: number | null;
  op: Op;
  memory: number;
  fresh: boolean;
  pulse: number;
};

type CalcAction = { type: "press"; key: string };

const initialState: CalcState = {
  display: "0",
  stored: null,
  op: null,
  memory: 0,
  fresh: false,
  pulse: 0,
};

const currentValue = (display: string) => {
  const value = Number(display);
  return Number.isFinite(value) ? value : 0;
};

const formatNumber = (value: number) => {
  if (!Number.isFinite(value)) return "Error";
  const rounded = Number(value.toFixed(12));
  return Object.is(rounded, -0) ? "0" : String(rounded);
};

const runOperation = (left: number, right: number, op: Op) => {
  if (op === "+") return left + right;
  if (op === "-") return left - right;
  if (op === "*") return left * right;
  if (op === "/") return right === 0 ? NaN : left / right;
  return right;
};

const calculateState = (state: CalcState, nextOp: Op): CalcState => {
  const current = currentValue(state.display);

  if (state.stored === null || state.op === null) {
    return { ...state, stored: nextOp ? current : null, op: nextOp, fresh: true, pulse: state.pulse + 1 };
  }

  if (state.fresh && nextOp) {
    return { ...state, op: nextOp, fresh: true };
  }

  const value = runOperation(state.stored, current, state.op);
  const display = formatNumber(value);

  if (display === "Error") {
    return { ...state, display, stored: null, op: null, fresh: true, pulse: state.pulse + 1 };
  }

  return {
    ...state,
    display,
    stored: nextOp ? value : null,
    op: nextOp,
    fresh: true,
    pulse: state.pulse + 1,
  };
};

const reducer = (state: CalcState, action: CalcAction): CalcState => {
  const key = action.key;
  const current = currentValue(state.display);

  if (/^\d$/.test(key) || key === ".") {
    if (state.display === "Error" || state.fresh) {
      return { ...state, display: key === "." ? "0." : key, fresh: false };
    }
    if (key === "." && state.display.includes(".")) return state;
    return { ...state, display: state.display === "0" && key !== "." ? key : state.display + key };
  }

  if (["+", "-", "*", "/"].includes(key)) {
    return calculateState(state, key as Op);
  }

  if (key === "=" || key === "Enter") {
    return calculateState(state, null);
  }

  if (key === "Escape" || key.toLowerCase() === "c") {
    return { ...initialState, memory: state.memory };
  }

  if (key === "%") {
    return { ...state, display: formatNumber(current / 100), fresh: false, pulse: state.pulse + 1 };
  }

  if (key === "+/-") {
    return { ...state, display: formatNumber(-current), fresh: false, pulse: state.pulse + 1 };
  }

  if (key === "MC") return { ...state, memory: 0 };
  if (key === "MR") return { ...state, display: formatNumber(state.memory), fresh: true, pulse: state.pulse + 1 };
  if (key === "M+") return { ...state, memory: state.memory + current };
  if (key === "M-") return { ...state, memory: state.memory - current };

  return state;
};

export default function BasicCalculator() {
  const [state, dispatch] = useReducer(reducer, initialState);
  const action = useCallback((key: string) => dispatch({ type: "press", key }), []);

  useEffect(() => {
    const onKey = (event: KeyboardEvent) => {
      if (/^\d$/.test(event.key) || [".", "+", "-", "*", "/", "=", "Enter", "Escape", "%", "c", "C"].includes(event.key)) {
        event.preventDefault();
        action(event.key);
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [action]);

  const btn = "rounded-xl border border-border bg-accent/60 hover:bg-accent text-foreground font-bold py-3 transition-colors";
  const opBtn = "rounded-xl bg-primary text-primary-foreground text-xl sm:text-2xl leading-none font-extrabold py-3 hover:bg-primary/90 transition-colors";

  return (
    <>
      <SEOHead title="Free Basic Calculator Online - Simple and Fast Calculator for Everyone | CalcHive" description="Free online basic calculator. Perform addition, subtraction, multiplication and division with memory functions instantly. Simple clean and fast. 100% free for everyone, no signup required." canonical="/basic-calculator" keywords="free basic calculator, simple calculator online free, calculator free online, basic math calculator free, free online calculator no download" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <style>{`@keyframes basicResultPulse{0%{transform:scale(.96);opacity:.72}100%{transform:scale(1);opacity:1}}`}</style>
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Basic Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free basic calculator for simple calculator online free arithmetic with memory functions and keyboard input.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-5 text-right shadow-lg mb-4"><p className="text-white/70 text-xs font-semibold uppercase tracking-widest">Display {state.memory !== 0 ? "- M" : ""}</p><p key={state.pulse} className="text-5xl font-black text-white break-all" style={{ animation: "basicResultPulse 180ms ease-out" }} data-testid="result-basic">{state.display}</p></div>
          <div className="grid grid-cols-4 gap-3">
            <button className={btn} onClick={() => action("C")}>C</button><button className={btn} onClick={() => action("+/-")}>+/-</button><button className={btn} onClick={() => action("%")}>%</button><button aria-label="Divide" className={opBtn} onClick={() => action("/")}>{DIVIDE}</button>
            {["7", "8", "9"].map((d) => <button key={d} className={btn} onClick={() => action(d)}>{d}</button>)}<button aria-label="Multiply" className={opBtn} onClick={() => action("*")}>{MULTIPLY}</button>
            {["4", "5", "6"].map((d) => <button key={d} className={btn} onClick={() => action(d)}>{d}</button>)}<button aria-label="Subtract" className={opBtn} onClick={() => action("-")}>-</button>
            {["1", "2", "3"].map((d) => <button key={d} className={btn} onClick={() => action(d)}>{d}</button>)}<button aria-label="Add" className={opBtn} onClick={() => action("+")}>+</button>
            <button className={btn} onClick={() => action("MC")}>MC</button><button className={btn} onClick={() => action("MR")}>MR</button><button className={btn} onClick={() => action("M+")}>M+</button><button className={btn} onClick={() => action("M-")}>M-</button>
            <button className={`${btn} col-span-2`} onClick={() => action("0")}>0</button><button className={btn} onClick={() => action(".")}>.</button><button aria-label="Equals" className={opBtn} onClick={() => action("=")}>=</button>
          </div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">Simple Free Online Calculator for Everyday Math</h2><p className="text-muted-foreground leading-relaxed">Use this calculator free online for addition, subtraction, multiplication, division, percentages, and sign changes.</p><h2 className="text-2xl font-bold text-foreground">How to Use the Basic Calculator</h2><p className="text-muted-foreground leading-relaxed">Click the buttons or use your keyboard. Memory buttons store and recall values like a standard handheld calculator.</p><h2 className="text-2xl font-bold text-foreground">Free Calculator for Everyone No Download Needed</h2><p className="text-muted-foreground leading-relaxed">This free online calculator no download tool works directly in your browser on mobile and desktop.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/basic-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


